import anthropic
import json
from concurrent.futures import ThreadPoolExecutor, as_completed
from dataclasses import dataclass, field
from typing import Any

client = anthropic.Anthropic()
MODEL = "claude-sonnet-4-6"

@dataclass
class SubTask:
    id: str
    description: str
    dependencies: list[str] = field(default_factory=list)
    is_leaf: bool = False
    result: Any = None


def decompose(task: str) -> list[SubTask]:
    """Ask the LLM to decompose a task into sub-tasks with explicit dependencies."""
    prompt = f"""Decompose the following task into sub-tasks.

Task: {task}

Rules:
- Each sub-task must be either a leaf (directly executable as one function call)
  or a non-leaf (requires further decomposition).
- List dependencies explicitly by sub-task ID.
- Leaf sub-tasks have descriptions that start with a tool name: search(), fetch(), summarize(), etc.

Respond ONLY with a JSON array. Example:
[
  {{"id": "t1", "description": "search('query')", "dependencies": [], "is_leaf": true}},
  {{"id": "t2", "description": "fetch('url from t1')", "dependencies": ["t1"], "is_leaf": true}},
  {{"id": "t3", "description": "Synthesize t1 and t2 into a report", "dependencies": ["t1","t2"], "is_leaf": false}}
]"""

    response = client.messages.create(
        model=MODEL,
        max_tokens=1024,
        messages=[{"role": "user", "content": prompt}],
    )
    raw = response.content[0].text.strip()
    if raw.startswith("```"):
        raw = "
".join(raw.split("
")[1:]).rstrip("` 
")
    data = json.loads(raw)
    return [SubTask(**item) for item in data]


def execute_leaf(task: SubTask, context: dict[str, Any]) -> Any:
    """Execute a leaf task. Substitute resolved dependency results into the description."""
    # Replace #Tn references with actual results
    desc = task.description
    for dep_id, dep_result in context.items():
        desc = desc.replace(f"#{dep_id}", str(dep_result))

    # In a real system, parse the tool name and call the actual tool.
    # Here we use an LLM call as a stand-in for the tool execution.
    response = client.messages.create(
        model=MODEL,
        max_tokens=512,
        messages=[{"role": "user", "content": f"Execute this task and return only the result:
{desc}"}],
    )
    return response.content[0].text.strip()


def solve_non_leaf(task: SubTask, context: dict[str, Any]) -> Any:
    """Solve a non-leaf by asking the LLM to synthesize dependency results."""
    dep_context = {dep: context[dep] for dep in task.dependencies if dep in context}
    prompt = f"""Task: {task.description}

Available results from sub-tasks:
{json.dumps(dep_context, indent=2)}

Produce the final result for this task."""
    response = client.messages.create(
        model=MODEL,
        max_tokens=1024,
        messages=[{"role": "user", "content": prompt}],
    )
    return response.content[0].text.strip()


def execute_plan(tasks: list[SubTask]) -> dict[str, Any]:
    """
    Execute a dependency-ordered plan, running independent tasks in parallel.
    Returns a dict mapping task id to result.
    """
    completed: dict[str, Any] = {}
    task_map = {t.id: t for t in tasks}

    while len(completed) < len(tasks):
        # Find tasks whose dependencies are all resolved
        ready = [
            t for t in tasks
            if t.id not in completed
            and all(dep in completed for dep in t.dependencies)
        ]
        if not ready:
            raise RuntimeError("Dependency cycle detected or unresolvable dependencies")

        # Run ready tasks in parallel
        with ThreadPoolExecutor(max_workers=len(ready)) as pool:
            futures = {}
            for task in ready:
                ctx = {dep: completed[dep] for dep in task.dependencies}
                if task.is_leaf:
                    futures[pool.submit(execute_leaf, task, ctx)] = task
                else:
                    futures[pool.submit(solve_non_leaf, task, ctx)] = task

            for future in as_completed(futures):
                task = futures[future]
                completed[task.id] = future.result()

    return completed

def verified_execute_leaf(task: SubTask, context: dict, max_retries: int = 2) -> Any:
    """Execute a leaf task, retrying if the result fails a validation check."""
    for attempt in range(max_retries + 1):
        result = execute_leaf(task, context)
        if is_valid_result(task, result):
            return result
        if attempt < max_retries:
            # Append failure context and retry
            context["_retry_hint"] = f"Previous attempt produced invalid result: {result[:100]}"
    raise ValueError(f"Task {task.id} failed validation after {max_retries + 1} attempts")


def is_valid_result(task: SubTask, result: str) -> bool:
    """
    Domain-specific validation. Examples:
    - A search task should return at least one URL.
    - A summary task should return >= 50 words.
    - A JSON-extraction task should produce parseable JSON.
    """
    if not result or len(result.strip()) < 10:
        return False
    if "search(" in task.description and "http" not in result.lower():
        return False
    return True

def detect_cycle(tasks: list[SubTask]) -> bool:
    """Return True if the dependency graph has a cycle."""
    task_map = {t.id: t for t in tasks}
    visiting, visited = set(), set()

    def dfs(tid: str) -> bool:
        if tid in visiting:
            return True  # cycle
        if tid in visited:
            return False
        visiting.add(tid)
        for dep in task_map[tid].dependencies:
            if dfs(dep):
                return True
        visiting.remove(tid)
        visited.add(tid)
        return False

    return any(dfs(t.id) for t in tasks if t.id not in visited)
